 34→/** Default number of head console lines to keep before truncation. */
 35→export const CAPTURE_HEAD_LINES = 50;
 36→/** Default number of tail console lines to keep after truncation. */
 37→export const CAPTURE_TAIL_LINES = 20;
 38→/** Maximum total bytes for captured console output before truncation. */
