 58→const VALIDATION_ERROR_PATTERNS = /Validation|Invalid|BadRequest|Forbidden|Unauthorized|NotFound/i;
 59→const RUNTIME_ERROR_TYPES = new Set(["TypeError", "ReferenceError", "SyntaxError", "RangeError", "URIError"]);
 60→
 61→/**
 62→ * Classify an error into a structured category using language-level signals.
 63→ * - validation: custom error subclasses or names suggesting deliberate input rejection
 64→ * - runtime: JS built-in error types indicating accidental failures
 65→ * - infrastructure: timeouts and system-level failures
 66→ */
 67→export function classifyError(errorType: string, message: string): ErrorCategory {
 68→  if (/timed?\s*out/i.test(message) || errorType === "ERR_SCRIPT_EXECUTION_TIMEOUT") {
 69→    return "infrastructure";
 70→  }
 71→  if (VALIDATION_ERROR_PATTERNS.test(errorType) || VALIDATION_ERROR_PATTERNS.test(message)) {
 72→    return "validation";
 73→  }
 74→  if (RUNTIME_ERROR_TYPES.has(errorType)) {
 75→    return "runtime";
 76→  }
 77→  return "unknown";
 78→}
