 99→/**
100→ * Set the project root for module resolution. When set, NODE_PATH includes
101→ * the project's node_modules directory so createRequire() resolves packages.
102→ */
103→export function setProjectRoot(projectRoot: string | null | undefined): void {
104→  if (projectRoot) {
105→    const nodeModules = path.join(projectRoot, "node_modules");
106→    const existing = process.env["NODE_PATH"] ?? "";
107→    if (!existing.split(path.delimiter).includes(nodeModules)) {
108→      process.env["NODE_PATH"] = existing ? `${nodeModules}${path.delimiter}${existing}` : nodeModules;
109→      // Force Node to re-read NODE_PATH for future require calls
110→      require("module").Module._initPaths();
111→    }
112→  }
113→}
