559→/**
560→ * Execute instrumented TypeScript source code with branch-recording callbacks.
561→ *
562→ * The instrumented source must contain __shatter_record() and __shatter_branch()
563→ * calls inserted by the instrumentor. This function defines those callbacks,
564→ * executes the code, and collects the branch decisions.
565→ */
566→export async function executeInstrumented(
567→  instrumentedSource: string,
568→  functionName: string,
569→  inputs: unknown[],
570→  mocks: MockConfig[] = [],
571→  sourceFilePath?: string,
572→): Promise<RawExecuteResult> {
573→  // Transpile instrumented TS to JS
574→  const jsResult = ts.transpileModule(instrumentedSource, {
575→    compilerOptions: {
576→      target: ts.ScriptTarget.ES2022,
577→      module: ts.ModuleKind.CommonJS,
578→      esModuleInterop: true,
579→      strict: true,
580→      jsx: ts.JsxEmit.ReactJSX,
581→    },
582→    ...(sourceFilePath ? { fileName: sourceFilePath } : {}),
583→  });
584→
585→  const linesExecuted: number[] = [];
586→  const branchDecisions: BranchDecision[] = [];
587→  const sideEffects: SideEffect[] = [];
588→  const externalCalls: ExternalCall[] = [];
589→  const scopeEvents: TraceEvent[] = [];
590→
591→  // Define the runtime callbacks
592→  const recordFn = (line: number): void => {
593→    linesExecuted.push(line);
594→  };
595→
596→  const branchFn = (
597→    branchId: number,
598→    line: number,
599→    conditionResult: boolean,
600→    symExpr: SymExpr,
601→  ): boolean => {
602→    const constraint: SymConstraint = symExpr.kind !== "unknown"
603→      ? { kind: "expr", expr: symExpr }
604→      : { kind: "unknown", hint: "unsupported expression" };
605→
606→    const decision: BranchDecision = {
607→      branch_id: branchId,
608→      line,
609→      taken: conditionResult,
610→      constraint,
611→    };
612→    branchDecisions.push(decision);
613→    scopeEvents.push({ type: "branch", decision });
614→
615→    return conditionResult;
616→  };
617→
618→  const scopeEventFn = (scopeId: number, kind: string): void => {
619→    const event: ScopeEvent = kind.startsWith("loop")
620→      ? { kind: kind as "loop_enter" | "loop_exit", loop_id: scopeId }
621→      : { kind: kind as "call_enter" | "call_exit", call_site_id: scopeId };
622→    scopeEvents.push({ type: "scope", event });
623→  };
624→
625→  // Build mock registry from MockConfig array
626→  const mockRegistry: Record<string, (...args: unknown[]) => unknown> = {};
627→  for (const mock of mocks) {
628→    if (mock.default_behavior === "passthrough") {
629→      continue;
630→    }
631→    let callIndex = 0;
632→    const returnValues = mock.return_values;
633→    mockRegistry[mock.symbol] = (...args: unknown[]): unknown => {
634→      if (returnValues.length > 0) {
635→        const idx = mock.default_behavior === "repeat_last"
636→          ? Math.min(callIndex, returnValues.length - 1)
637→          : callIndex % returnValues.length;
638→        callIndex++;
639→        return returnValues[idx];
640→      }
641→      return undefined;
642→    };
643→  }
644→
645→  // Mock call recorder
646→  const mockCallFn = (
647→    moduleName: string,
648→    symbolName: string,
649→    args: unknown[],
650→    returnValue: unknown,
651→  ): void => {
652→    externalCalls.push({
653→      symbol: `${moduleName}:${symbolName}`,
654→      args: Array.isArray(args) ? args : [],
655→      return_value: returnValue,
656→    });
657→  };
658→
659→  // Build the execution context with capturing console and process
660→  const capturingConsole = createCapturingConsole(sideEffects);
661→  const capturingProc = createCapturingProcess(sideEffects);
662→  const rawRequire = sourceFilePath ? createRequire(path.resolve(sourceFilePath)) : require;
663→  const sandboxRequire = wrapRequireWithReactShim(rawRequire, sourceFilePath);
664→  const moduleExports: Record<string, unknown> = {};
665→  const moduleObj = { exports: moduleExports };
666→
667→  const sandbox = vm.createContext({
668→    module: moduleObj,
669→    exports: moduleExports,
670→    require: sandboxRequire,
671→    console: capturingConsole,
672→    process: capturingProc,
673→    Buffer,
674→    setTimeout,
675→    clearTimeout,
676→    setInterval,
677→    clearInterval,
678→    ...(sourceFilePath ? { __filename: sourceFilePath, __dirname: path.dirname(sourceFilePath) } : {}),
679→    [RECORD_FUNCTION]: recordFn,
680→    [BRANCH_FUNCTION]: branchFn,
681→    [SCOPE_EVENT_FUNCTION]: scopeEventFn,
682→    [MOCK_REGISTRY]: mockRegistry,
683→    [MOCK_CALL_FUNCTION]: mockCallFn,
684→  });
685→
686→  vm.runInContext(jsResult.outputText, sandbox, { filename: sourceFilePath ?? "instrumented.js", timeout: getExecTimeoutMs() });
687→
688→  // Resolve the function from the module exports
689→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
690→
691→  // Snapshot module-level variables before execution
692→  const exportKeys = Object.keys(finalExports.exports).filter(
693→    (k) => typeof finalExports.exports[k] !== "function",
694→  );
695→  const beforeSnapshot = new Map<string, unknown>();
696→  for (const key of exportKeys) {
697→    beforeSnapshot.set(key, structuredClone(finalExports.exports[key]));
698→  }
699→
700→  const fn = finalExports.exports[functionName];
701→
702→  if (typeof fn !== "function") {
703→    throw new Error(
704→      `Function "${functionName}" not found in instrumented module exports. ` +
705→      `Available: ${Object.keys(finalExports.exports).join(", ")}`,
706→    );
707→  }
708→
709→  const reconstructedInputs = inputs.map(reconstructValue);
710→  const metrics = await measureExecution(
711→    () => (fn as (...args: unknown[]) => unknown)(...reconstructedInputs),
712→  );
713→
714→  if (metrics.thrownError) {
715→    sideEffects.push({
716→      kind: "thrown_error",
717→      error_type: metrics.thrownError.error_type,
718→      message: metrics.thrownError.message,
719→      stack: metrics.thrownError.stack,
720→    });
721→  }
722→
723→  // Detect module-level variable changes after execution
724→  for (const key of exportKeys) {
725→    const before = beforeSnapshot.get(key);
726→    const after = finalExports.exports[key];
727→    if (JSON.stringify(before) !== JSON.stringify(after)) {
728→      sideEffects.push({
729→        kind: "global_state_change",
730→        variable: key,
731→        before,
732→        after,
733→      });
734→    }
735→  }
736→
737→  // Build path_constraints: the conjunction of constraints along the taken path
738→  const pathConstraints = branchDecisions.map((bd) => bd.constraint);
739→
740→  return {
741→    return_value: metrics.returnValue ?? null,
742→    thrown_error: metrics.thrownError,
743→    side_effects: sideEffects,
744→    branch_path: branchDecisions,
745→    path_constraints: pathConstraints,
746→    lines_executed: linesExecuted,
747→    performance: metrics.performance,
748→    calls_to_external: externalCalls,
749→    scope_events: scopeEvents,
750→  };
751→}
752→
753→/**
754→ * Build a full ExecuteResponse from a raw execution result.
755→ * Applies side-effect truncation before assembling the response.
756→ */
757→export function buildExecuteResponse(
758→  id: number,
759→  protocolVersion: string,
760→  rawResult: RawExecuteResult,
761→): ExecuteResponse {
762→  const { effects, truncation } = truncateSideEffects(rawResult.side_effects);
763→
764→  const response: ExecuteResponse = {
765→    protocol_version: protocolVersion,
766→    id,
767→    status: "execute",
768→    return_value: rawResult.return_value,
769→    thrown_error: rawResult.thrown_error,
770→    branch_path: rawResult.branch_path,
771→    lines_executed: rawResult.lines_executed,
772→    calls_to_external: rawResult.calls_to_external,
773→    path_constraints: rawResult.path_constraints,
774→    side_effects: effects,
775→    performance: rawResult.performance,
776→    scope_events: rawResult.scope_events,
777→  };
778→
779→  if (truncation) {
780→    response.capture_truncation = truncation;
781→  }
782→
783→  return response;
784→}
